"""
This module represents the Checkers board.
"""

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize pieces on the board
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, 'black')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece(row, col, 'white')

    def get_piece(self, row, col):
        return self.board[row][col]

    def move_piece(self, start_row, start_col, end_row, end_col):
        piece = self.get_piece(start_row, start_col)
        if piece is not None:
            self.board[end_row][end_col] = piece
            self.board[start_row][start_col] = None

    def king_piece(self, row, col):
        piece = self.get_piece(row, col)
        if piece and (piece.owner == 'black' and row == 0 or piece.owner == 'white' and row == 7):
            piece.is_king = True

class Piece:
    def __init__(self, row, col, owner):
        self.row = row
        self.col = col
        self.owner = owner
        self.is_king = False
```

