from board import Board

class Player:
    def __init__(self, color):
        self.color = color

    def make_move(self, board, start_row, start_col, end_row, end_col):
        if board.get_piece(start_row, start_col) and board.get_piece(start_row, start_col).owner == self.color:
            board.move_piece(start_row, start_col, end_row, end_col)
            if (self.color == 'black' and end_row == 0) or (self.color == 'white' and end_row == 7):
                board.king_piece(end_row, end_col)
